fn update_events_borders<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            let new_focus =
                if *x >= 64 && *x < 176 && *y >= 94 && *y < 146 { Some(0) }
                else if *x >= 304 && *x < 416 && *y >= 94 && *y < 146 { Some(1) }
                else { None };
            *FOCUSED.lock().unwrap() = new_focus;
            if *x >= 64 && *x < 176 && *y >= 94 && *y < 146 {
                state.nav(&["Margin"]);
            }
            if *x >= 304 && *x < 416 && *y >= 94 && *y < 146 {
                state.nav(&["Clickable"]);
            }
        }
    }
}

