fn update_changes_borders(backend: &mut dyn Backend, _changes: &[(&str, &str)]) {
    {
        let focused = *FOCUSED.lock().unwrap();
        let mut last = LAST_DRAWN_FOCUS.lock().unwrap();
        if *last != focused {
            *last = focused;
            drop(last);
            draw_focus_borders(backend, focused);
        }
    }
}

