fn update_changes_dynamic(backend: &mut dyn Backend, changes: &[(&str, &str)]) {
    if changes.iter().any(|&(n, _)| n == "parameter One" || n == "parameter Two") {
        backend.render(&mut |fb, stride| {
            for &(name, val) in changes {
                match name {
                    "parameter One" => atlas_3().blit(fb, stride, 11, 164,
                        &format!("{:<26}", val)),
                    "parameter Two" => atlas_3().blit(fb, stride, 11, 225,
                        &format!("{:<26}", val)),
                    _ => {}
                }
            }
        });
    }
    {
        let focused = *FOCUSED.lock().unwrap();
        let mut last = LAST_DRAWN_FOCUS.lock().unwrap();
        if *last != focused {
            *last = focused;
            drop(last);
            draw_focus_dynamic(backend, focused);
        }
    }
}

