fn update_changes_progress(backend: &mut dyn Backend, changes: &[(&str, &str)]) {
    if changes.iter().any(|&(n, _)| n == "parameter One") {
        backend.render(&mut |fb, stride| {
            for &(name, val) in changes {
                if name == "parameter One" {
                    atlas_3().blit(fb, stride, 251, 235,
                        &format!("{:<12}", val));
                }
            }
        });
    }
    for &(name, val) in changes {
        if name == "parameter One" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (478.0_f32 * v) as usize;
                let prev = PROG_1_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(1, 151, filled, 38, rgb!(255, 255, 255)); }
                        if filled < 478 { backend.fill_rect(1 + filled, 151, 478 - filled, 38, rgb!(0, 0, 0)); }
                    } else if filled > prev {
                        backend.fill_rect(1 + prev, 151, filled - prev, 38, rgb!(255, 255, 255));
                    } else {
                        backend.fill_rect(1 + filled, 151, prev - filled, 38, rgb!(0, 0, 0));
                    }
                }
            }
        }
        if name == "parameter Two" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (458.0_f32 * v) as usize;
                let prev = PROG_2_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(11, 201, filled, 18, rgb!(0, 255, 0)); }
                        if filled < 458 { backend.fill_rect(11 + filled, 201, 458 - filled, 18, rgb!(40, 40, 40)); }
                    } else if filled > prev {
                        backend.fill_rect(11 + prev, 201, filled - prev, 18, rgb!(0, 255, 0));
                    } else {
                        backend.fill_rect(11 + filled, 201, prev - filled, 18, rgb!(40, 40, 40));
                    }
                }
            }
        }
        if name == "parameter One" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (218.0_f32 * v) as usize;
                let prev = PROG_3_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(11, 241, filled, 20, rgb!(0, 0, 255)); }
                        if filled < 218 { backend.fill_rect(11 + filled, 241, 218 - filled, 20, rgb!(40, 40, 40)); }
                    } else if filled > prev {
                        backend.fill_rect(11 + prev, 241, filled - prev, 20, rgb!(0, 0, 255));
                    } else {
                        backend.fill_rect(11 + filled, 241, prev - filled, 20, rgb!(40, 40, 40));
                    }
                }
            }
        }
    }
    {
        let focused = *FOCUSED.lock().unwrap();
        let mut last = LAST_DRAWN_FOCUS.lock().unwrap();
        if *last != focused {
            *last = focused;
            drop(last);
            draw_focus_progress(backend, focused);
        }
    }
}

